import re
import sys
from typing import List, Optional, Union

__all__ = ["ReceiveBuffer"]


# Operations we want to support:
# - find next \r\n or \r\n\r\n (\n or \n\n are also acceptable),
#   or wait until there is one
# - read at-most-N bytes
# Goals:
# - on average, do this fast
# - worst case, do this in O(n) where n is the number of bytes processed
# Plan:
# - store bytearray, offset, how far we've searched for a separator token
# - use the how-far-we've-searched data to avoid rescanning
# - while doing a stream of uninterrupted processing, advance offset instead
#   of constantly copying
# WARNING:
# - I haven't benchmarked or profiled any of this yet.
#
# Note that starting in Python 3.4, deleting the initial n bytes from a
# bytearray is amortized O(n), thanks to some excellent work by Antoine
# Martin:
#
#     https://bugs.python.org/issue19087
#
# This means that if we only supported 3.4+, we could get rid of the code here
# involving self._start and self.compress, because it's doing exactly the same
# thing that bytearray now does internally.
#
# BUT unfortunately, we still support 2.7, and reading short segments out of a
# long buffer MUST be O(bytes read) to avoid DoS issues, so we can't actually
# delete this code. Yet:
#
#     https://pythonclock.org/
#
# (Two things to double-check first though: make sure PyPy also has the
# optimization, and benchmark to make sure it's a win, since we do have a
# slightly clever thing where we delay calling compress() until we've
# processed a whole event, which could in theory be slightly more efficient
# than the internal bytearray support.)
blank_line_regex = re.compile(b"\n\r?\n", re.MULTILINE)


class ReceiveBuffer:
    def __init__(self) -> None:
        """Initialize an empty receive buffer.

        The buffer stores incoming bytes and tracks how far we've searched
        for single-line and multiple-line (blank-line separated) boundaries
        to avoid rescanning already-checked regions.
        """
        self._data = bytearray()
        self._next_line_search = 0
        self._multiple_lines_search = 0

    def __iadd__(self, byteslike: Union[bytes, bytearray]) -> "ReceiveBuffer":
        """Append bytes to the receive buffer in-place."""
        self._data += byteslike
        return self

    def __bool__(self) -> bool:
        """Truthiness indicates whether the buffer contains any bytes."""
        return bool(len(self))

    def __len__(self) -> int:
        """Return the number of bytes currently buffered."""
        return len(self._data)

    # for @property unprocessed_data
    def __bytes__(self) -> bytes:
        """Return a bytes copy of the current unprocessed data."""
        return bytes(self._data)

    def _extract(self, count: int) -> bytearray:
        """Remove and return the first `count` bytes from the buffer.

        This resets the search cursors so subsequent searches start fresh.
        """
        # extracting an initial slice of the data buffer and return it
        out = self._data[:count]
        del self._data[:count]

        self._next_line_search = 0
        self._multiple_lines_search = 0

        return out

    def maybe_extract_at_most(self, count: int) -> Optional[bytearray]:
        """
        Extract a fixed number of bytes from the buffer.

        If the buffer is empty this returns None; otherwise it extracts up to
        `count` bytes (exactly `count` if available, or fewer if the buffer
        contains fewer bytes).
        """
        out = self._data[:count]
        if not out:
            return None

        return self._extract(count)

    def maybe_extract_next_line(self) -> Optional[bytearray]:
        """
        Extract the first line, if it is completed in the buffer.

        A line is recognized by the presence of a CRLF sequence (b"\r\n").
        This method avoids rescanning regions of the buffer that were
        previously inspected.
        """
        # Only search in buffer space that we've not already looked at.
        search_start_index = max(0, self._next_line_search - 1)
        partial_idx = self._data.find(b"\r\n", search_start_index)

        if partial_idx == -1:
            self._next_line_search = len(self._data)
            return None

        # + 2 is to compensate len(b"\r\n")
        idx = partial_idx + 2

        return self._extract(idx)

    def maybe_extract_lines(self) -> Optional[List[bytearray]]:
        """
        Extract everything up to the first blank line, and return a list of lines.

        The returned list contains each line (including its line ending, e.g.
        b'\\r\\n' or b'\\n') as a bytearray. The terminating blank line is
        removed from the returned list (but is consumed from the buffer).
        """
        # Handle the case where we have an immediate empty line.
        if self._data[:1] == b"\n":
            self._extract(1)
            return []

        if self._data[:2] == b"\r\n":
            self._extract(2)
            return []

        # Only search in buffer space that we've not already looked at.
        match = blank_line_regex.search(self._data, self._multiple_lines_search)
        if match is None:
            self._multiple_lines_search = max(0, len(self._data) - 2)
            return None

        # Extract up through the matched blank-line sequence.
        end = match.end()
        block = self._extract(end)

        # Split into lines keeping line endings, then drop the final blank line.
        # bytes.splitlines(keepends=True) works on bytearray as well.
        lines = block.splitlines(True)

        # The separator that ended the header block will be represented as the
        # final element(s) returned by splitlines(True). Drop that final
        # element so callers receive only the header lines themselves.
        if lines:
            lines = lines[:-1]
        # Convert each bytes element to bytearray for consistency with other methods.
        return [bytearray(x) for x in lines]


def is_next_line_obviously_invalid_request_line(line: Union[bytes, bytearray]) -> bool:
    """Return True if the given line appears to be an invalid HTTP request line.

    This performs a heuristic check: after stripping trailing CR/LF, the
    request-line should contain at least two spaces (separating method,
    target, and version) and the final token should start with b'HTTP/'.
    If these conditions are not met, we consider the line obviously invalid.
    """
    if not line:
        return True
    data = bytes(line).rstrip(b"\r\n")
    if not data:
        return True
    # Must contain at least two spaces: METHOD SP REQUEST-TARGET SP HTTP/VERSION
    if data.count(b" ") < 2:
        return True
    parts = data.split(b" ")
    if not parts:
        return True
    if not parts[-1].startswith(b"HTTP/"):
        return True
    return False